    <script>
      (function() {
        var core = document.currentScript.closest('.ac6-core');
        var raw = core.querySelector('.raw-data').textContent;
        var dest = core.querySelector('.ac6-content');
        var titleEl = core.querySelector('#dynamic-title');

        var _ = {
          e: function(s) {
            return String(s)
              .replace(/&/g,'&amp;')
              .replace(/</g,'&lt;')
              .replace(/>/g,'&gt;')
              .replace(/"/g,'&quot;');
          },
          hl: function(s) {
            return String(s)
              .replace(/(\d+)\/(?:\d+)/g, function(m) {
                var parts = m.split('/');
                var cur = parseInt(parts[0]);
                var max = parseInt(parts[1]);
                if (cur === 0) return '<span class="hl-dmg">' + m + '</span>';
                if (cur < max * 0.3) return '<span class="hl-warn">' + m + '</span>';
                return m;
              })
              .replace(/(-|\+)\d+/g, function(m) {
                if (m.charAt(0) === '-') return '<span class="hl-dmg">' + m + '</span>';
                if (m.charAt(0) === '+') return '<span class="hl-heal">' + m + '</span>';
                return m;
              })
              .replace(/(\d+)%/g, '<span class="hl-heal">$1</span>%')
              .replace(/(?:重击|击穿|弱点)/g, '<span class="hl-crit">$&</span>')
              .replace(/TIER(\d)/g, 'TIER<span class="hl-tier">$1</span>')
              .replace(/未击穿/g, '<span class="hl-miss">$&</span>')
              .replace(/未命中/g, '<span class="hl-miss">$&</span>')
              .replace(/交感同操/g, '<span class="hl-resonance">$&</span>')
              .replace(/(?:蓝方|红方|我方|友方|敌对)/g, function(m) {
                if (m === '蓝方') return '<span class="hl-blue">' + m + '</span>';
                if (m === '红方') return '<span class="hl-red">' + m + '</span>';
                return m;
              })
              .replace(/(?:命中|对抗结果):\s*(.+)/g, function(m, result) {
                if (result.indexOf('命中') !== -1 || result.indexOf('重击') !== -1) {
                  return m.replace(result, '<span class="hl-crit">' + result + '</span>');
                }
                if (result.indexOf('未命中') !== -1) {
                  return m.replace(result, '<span class="hl-miss">' + result + '</span>');
                }
                return m;
              })
              .replace(/d20=(\d+)/g, 'd20=<span class="hl-dice">$1</span>')
              .replace(/index=(\d+)/g, 'index=<span class="hl-warn">$1</span>')
              .replace(/(?:EWR|追踪性能):\s*(\d+)/g, function(m, v) {
                return m.replace(v, '<span class="hl-tier">' + v + '</span>');
              })
              .replace(/(?:越阶穿透|平阶|越阶未击穿)/g, function(m) {
                if (m.indexOf('穿透') !== -1 || m.indexOf('平阶') !== -1) {
                  return '<span class="hl-crit">' + m + '</span>';
                }
                return '<span class="hl-miss">' + m + '</span>';
              })
              .replace(/(?:干扰成功|干扰失败|普通成功|强成功)/g, function(m) {
                if (m.indexOf('失败') !== -1) return '<span class="hl-dmg">' + m + '</span>';
                if (m.indexOf('强成功') !== -1) return '<span class="hl-crit">' + m + '</span>';
                return '<span class="hl-heal">' + m + '</span>';
              })
              .replace(/(?:胜利|失败|撤离|平局)/g, function(m) {
                if (m === '胜利') return '<span class="hl-heal">' + m + '</span>';
                if (m === '失败') return '<span class="hl-dmg">' + m + '</span>';
                return '<span class="hl-warn">' + m + '</span>';
              });
          }
        };

        function parsePipeLine(t) {
          var parts = t.split('|').filter(function(p) { return p.trim(); });
          var html = '<div class="ui-data-row">';
          for (var i = 0; i < parts.length; i++) {
            var p = parts[i].trim();
            var colonIdx = p.indexOf(':');
            if (colonIdx !== -1) {
              var k = p.substring(0, colonIdx).trim();
              var v = p.substring(colonIdx + 1).trim();
              html += '<div class="ui-tag"><span class="ui-tag-key">' + _.e(k) + '</span><span class="ui-tag-val">' + _.hl(_.e(v)) + '</span></div>';
            } else {
              html += '<div class="ui-tag"><span class="ui-tag-val">' + _.hl(_.e(p)) + '</span></div>';
            }
          }
          return html + '</div>';
        }

        function parseUnitCard(line) {
          var t = line.trim();
          var isResonance = t.indexOf('交感同操') !== -1;
          var extraClass = isResonance ? ' resonance' : '';
          var name = '';
          var stats = '';
          var weapons = [];
          var subUnits = [];

          if (isResonance) {
            var m = t.match(/^-\s+(.+?)\s*\(交感同操\)\s*\|\s*(.+)$/);
            if (m) {
              name = m[1].trim() + '<span class="resonance-tag">[交感同操]</span>';
              stats = m[2].trim();
              var pairs = stats.split(',').map(function(s) { return s.trim(); });
              var statHtml = '<div class="ui-unit-row">';
              for (var i = 0; i < pairs.length; i++) {
                var pair = pairs[i];
                var ci = pair.indexOf(':');
                if (ci !== -1) {
                  var k = pair.substring(0, ci).trim();
                  var v = pair.substring(ci + 1).trim();
                  statHtml += '<div class="ui-unit-kv"><span class="ui-unit-key">' + _.e(k) + '</span><span class="ui-unit-val">' + _.hl(_.e(v)) + '</span></div>';
                }
              }
              statHtml += '</div>';
              return '<div class="ui-unit-card' + extraClass + '"><div class="ui-unit-name">' + name + '</div>' + statHtml + '</div>';
            }
          } else {
            var m = t.match(/^-\s+(.+?)\s*\|\s*(.+)$/);
            if (m) {
              name = m[1].trim();
              stats = m[2].trim();
              var statPairs = stats.split('|').map(function(s) { return s.trim(); });
              var statHtml = '<div class="ui-unit-row">';
              for (var i = 0; i < statPairs.length; i++) {
                var pair = statPairs[i];
                var ci = pair.indexOf(':');
                if (ci === -1) continue;
                var k = pair.substring(0, ci).trim();
                var v = pair.substring(ci + 1).trim();
                if (k === '武器') {
                  var weaponList = v.replace(/[\[\]]/g, '').split(',');
                  for (var j = 0; j < weaponList.length; j++) {
                    weapons.push(weaponList[j].trim());
                  }
                } else {
                  statHtml += '<div class="ui-unit-kv"><span class="ui-unit-key">' + _.e(k) + '</span><span class="ui-unit-val">' + _.hl(_.e(v)) + '</span></div>';
                }
              }
              statHtml += '</div>';
              var weaponHtml = '';
              if (weapons.length > 0) {
                weaponHtml = '<div class="ui-unit-weapons">';
                for (var j = 0; j < weapons.length; j++) {
                  weaponHtml += '<div class="ui-unit-weapon">' + _.hl(_.e(weapons[j])) + '</div>';
                }
                weaponHtml += '</div>';
              }
              return '<div class="ui-unit-card' + extraClass + '"><div class="ui-unit-name">' + _.e(name) + '</div>' + statHtml + weaponHtml + '</div>';
            }
          }
          return '<div class="ui-list-item"><div class="ui-li-icon"></div><div class="ui-li-text">' + _.hl(_.e(t.replace(/^-\s+/, ''))) + '</div></div>';
        }

        function parseEwrBlock(lines, startIdx) {
          var html = '';
          var ewrData = {};
          for (var i = startIdx; i < lines.length; i++) {
            var line = lines[i];
            var t = line.trim();
            if (!t || t.charAt(0) === '#') continue;
            if (t.indexOf('回合:') !== -1 || t.indexOf('先攻判定') !== -1 || t.indexOf('行动:') !== -1 || t.indexOf('资源结算') !== -1 || t.indexOf('战斗总结') !== -1) {
              return { html: html, nextIdx: i };
            }
